331	    fn run_invocation_streaming(
332	        &self,
333	        invocation: &CodexInvocation,
334	        agent_id: Option<&AgentId>,
335	        sink: &mut dyn FnMut(AgentStreamEvent),
336	    ) -> Result<String, AgentError> {
337	        let mut command = Command::new(&invocation.program);
338	        command
339	            .args(&invocation.args)
340	            .stdin(Stdio::piped())
341	            .stdout(Stdio::piped())
342	            .stderr(Stdio::piped());
343	        configure_agent_child_process(&mut command);
344	        let mut child = command.spawn()?;
345	        let child_pid = child.id();
346	        let _process_guard = self.shutdown.register(child.id());
347	        if let Some(agent_id) = agent_id {
348	            self.state
349	                .lock()
350	                .expect("codex backend state mutex poisoned")
351	                .active_processes
352	                .insert(agent_id.clone(), child_pid);
353	        }
354	
355	        if let Some(stdin) = child.stdin.as_mut() {
356	            stdin.write_all(invocation.stdin.as_bytes())?;
357	        }
358	        drop(child.stdin.take());
359	
360	        let stderr_reader = child.stderr.take().map(|mut stderr| {
445	            if let Some(text) = text {
