522	struct BackendCommand<'a> {
523	    token: &'a str,
524	    args: &'a str,
525	}
526	
527	fn parse_backend_command(command: &str) -> Option<BackendCommand<'_>> {
528	    let rest = command.trim().strip_prefix('/')?;
529	    let token_end = rest.find(char::is_whitespace).unwrap_or(rest.len());
530	    let token = &rest[..token_end];
531	    if token.is_empty() {
532	        return None;
533	    }
534	    Some(BackendCommand {
535	        token,
536	        args: rest[token_end..].trim(),
537	    })
538	}
