541	    let command = parse_backend_command(command)
542	        .map(|command| format!("/{}", command.token))
543	        .unwrap_or_else(|| command.to_string());
544	    AgentError::UnsupportedAgentCommand {
545	        agent_id: agent_id.clone(),
546	        command,
547	    }
548	}
