556	fn parse_codex_output(output: &str) -> ParsedCodexOutput {
557	    let mut parsed = ParsedCodexOutput::default();
558	    for line in output.lines() {
559	        let compact = compact_json_line(line);
560	        if compact.contains(r#""type":"thread.started""#) {
561	            parsed.thread_id = json_string_field(&compact, "thread_id").or(parsed.thread_id);
562	        }
563	        if compact.contains(r#""type":"item.completed""#)
564	            && compact.contains(r#""type":"agent_message""#)
565	            && let Some(text) = json_string_field(&compact, "text")
585	    let compact = compact_json_line(line);
586	    if compact.contains(r#""type":"item.completed""#)
587	        && compact.contains(r#""type":"agent_message""#)
588	    {
589	        return json_string_field(&compact, "text").map(AgentStreamEvent::AgentMessage);
590	    }
591	    if compact.contains(r#""type":"error""#) {
592	        return json_string_field(&compact, "message").map(AgentStreamEvent::Error);
593	    }
594	    if compact.contains(r#""type":"thread.started""#) {
595	        return json_string_field(&compact, "thread_id")
596	            .map(|thread_id| AgentStreamEvent::Status(format!("Codex session {thread_id}")));
597	    }
598	    if compact.contains(r#""type":"turn.started""#) {
599	        return Some(AgentStreamEvent::Status("Codex is working".to_string()));
600	    }
601	    None
602	}
